import{_ as o,c as e,o as t,a6 as c}from"./chunks/framework.Du4yMC9e.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"others/vmtu/config.md","filePath":"others/vmtu/config.md","lastUpdated":1719832393000}'),a={name:"others/vmtu/config.md"},d=c('<p>模组会在<code>.minecraft/&lt;mcversion&gt;/config/</code>文件夹创建名为<code>vmtranslationupdate</code>的配置文件（1.12.2后缀是.cfg，其他版本为.toml）。</p><p>配置项如下：</p><ol><li>自动根据切换语言（<code>autoSwitchLanguage</code>）：默认禁用，在安装了<a href="https://modrinth.com/mod/stenographer" target="_blank" rel="noreferrer">Stenographer</a>模组后将禁用。</li><li>自动检测整合包汉化版本更新（<code>checkModPackTranslationUpdate</code>）：默认启用，在每次玩家进入世界后检查整合包汉化更新。</li><li>自动下载VM汉化资源包（<code>autoDownloadVMTranslationPack</code>）：默认启用，在每次加载游戏时下载VM汉化资源包。</li><li>自动安装VM汉化资源包（<code>autoInstallVMTranslationPack</code>）：默认启用，在每次加载游戏时安装VM汉化资源包。前置为自动下载VM汉化资源包（<code>autoDownloadVMTranslationPack</code>）必须开启。</li><li>显示小提示（<code>displayTips</code>）：默认启用，在玩家进入存档后每25分钟（可配置）在聊天栏发送一条知识。</li><li>检测玩家名称彩蛋（<code>playerNameCheck</code>）：默认启用，在特定玩家进入存档后用于称呼的玩家英文名称将改为定义的专属称呼。</li><li>选择切换语言为（<code>switchLanguage</code>）：默认为<code>zh_cn</code>, 选择要切换的语言（当自动根据切换语言被打开时在每次游戏启动时生效），此处应填语言代码。</li><li>更新检测链接（<code>modPackTranslationUpdateCheckUrl</code>）：只能填写指向一个txt文件的链接，链接的txt文件只能有此整合包翻译版本号。如：<code>https://vmct-cn.top/modpacks/example/update.txt</code></li><li>下载链接（<code>modPackTranslationUrl</code>）：填写一个指向整合包下载页的链接。如：<code>https://vmct-cn.top/modpacks/example/</code></li><li>获取知识内容的链接（<code>tipsUrl</code>）：前置为显示小提示（<code>displayTips</code>）必须开启。用于知识显示功能，此链接必须指向一个txt文件。</li><li>整合包翻译版本（<code>modPackTranslationVersion</code>）：整合包汉化本地版本号。</li><li>发送知识的时间间隔（分钟）（<code>tipsMinutes</code>）：用于知识显示功能，可配置显示的时间间隔，单位为分钟。</li><li>下载资源包的链接（<code>translationPackUrl</code>）：填写一个汉化资源包下载链接，但不包括文件名及其后缀。如：<code>https://cdn.modrinth.com/data/IDWIdXwS/versions/V5YtW17O/VM汉化组模组汉化包1.20.zip</code> 你只需要填写 <code>https://cdn.modrinth.com/data/IDWIdXwS/versions/V5YtW17O/</code></li><li>资源包的文件名（<code>translationPackName</code>）：填写汉化资源包名称，不要带文件名后缀。如：VM汉化组模组汉化包1.20</li><li>玩家对应称呼的链接（<code>nameUrl</code>）：前置为检测玩家名称彩蛋（<code>playerNameCheck</code>）必须开启。用于定义称呼玩家的名称，必须为一个指向json文件的链接。如：<code>https://vmct-cn.top/name.json</code>。格式为<code>&quot;玩家名&quot;: &quot;称呼&quot;</code></li></ol>',3),i=[d];function l(n,s,r,p,m,_){return t(),e("div",null,i)}const k=o(a,[["render",l]]);export{u as __pageData,k as default};
